I'll modify the gateway firmware to change the LED color based on connectivity to the Pi. The LED should be green when MQTT is connected and red when disconnected.

```cpp
// FILE: firmware/gateway/src/main.cpp
#include <Arduino.h>
#include <WiFi.h>
#include <PubSubClient.h>
#include <ArduinoJson.h>
#include <esp_wifi.h>
#include <esp_mac.h>
#include <Preferences.h>

// ===== LED Control =====
#define LED_PIN 38
#define LED_CHANNEL 0

void set_led_color(uint8_t r, uint8_t g, uint8_t b) {
	neopixelWrite(LED_PIN, r, g, b);
}

// ===== Configuration =====
#define AP_SSID "ParleyNet"
#define AP_PASSWORD "parley123"
#define AP_CHANNEL 6
#define MQTT_BROKER "192.168.4.2"
#define MQTT_PORT 1883
#define HEARTBEAT_INTERVAL 5000
#define PUBLISH_INTERVAL 10000

// ===== Global State =====
WiFiClient espClient;
PubSubClient mqtt(espClient);
Preferences prefs;

unsigned long lastHeartbeat = 0;
unsigned long lastPublish = 0;
String nodeId = "gateway";
String fwVersion = "gateway-1.0.0";
uint8_t gatewayMAC[6];

// ===== WiFi AP Setup =====
void setup_ap() {
	WiFi.mode(WIFI_AP);
	WiFi.softAP(AP_SSID, AP_PASSWORD, AP_CHANNEL);

	IPAddress local_ip(192, 168, 4, 1);
	IPAddress gateway(192, 168, 4, 1);
	IPAddress subnet(255, 255, 255, 0);
	WiFi.softAPConfig(local_ip, gateway, subnet);

	esp_wifi_get_mac(WIFI_IF_AP, gatewayMAC);

	Serial.println("AP Started:");
	Serial.print("  SSID: ");
	Serial.println(AP_SSID);
	Serial.print("  IP: ");
	Serial.println(WiFi.softAPIP());
	Serial.print("  MAC: ");
	for (int i = 0; i < 6; i++) {
		Serial.printf("%02x", gatewayMAC[i]);
		if (i < 5) Serial.print(":");
	}
	Serial.println();
}

// ===== MQTT =====
void mqtt_callback(char* topic, byte* payload, unsigned int length) {
	String topicStr = String(topic);

	if (topicStr.startsWith("nodes/" + nodeId + "/cmd/")) {
		String channel = topicStr.substring(String("nodes/" + nodeId + "/cmd/").length());

		StaticJsonDocument<512> doc;
		DeserializationError err = deserializeJson(doc, payload, length);

		if (err) {
			Serial.println("JSON parse error in command");
			return;
		}

		if (channel == "reboot") {
			Serial.println("Reboot command received");
			ESP.restart();
		}
	}
}

void mqtt_reconnect() {
	static unsigned long lastAttempt = 0;
	if (millis() - lastAttempt < 5000) return;
	lastAttempt = millis();

	Serial.print("Connecting to MQTT broker at ");
	Serial.print(MQTT_BROKER);
	Serial.print(":");
	Serial.print(MQTT_PORT);
	Serial.print("...");

	if (mqtt.connect(nodeId.c_str())) {
		Serial.println(" connected!");
		set_led_color(0, 255, 0);  // GREEN when connected

		mqtt.subscribe(("nodes/" + nodeId + "/cmd/#").c_str());

		// Publish initial registration
		StaticJsonDocument<256> reg;
		reg["node_id"] = nodeId;
		reg["type"] = "gateway";
		reg["fw"] = fwVersion;

		char macStr[18];
		snprintf(macStr, sizeof(macStr), "%02x:%02x:%02x:%02x:%02x:%02x",
			gatewayMAC[0], gatewayMAC[1], gatewayMAC[2],
			gatewayMAC[3], gatewayMAC[4], gatewayMAC[5]);
		reg["mac"] = macStr;
		reg["ip"] = WiFi.softAPIP().toString();

		String regPayload;
		serializeJson(reg, regPayload);
		mqtt.publish(("nodes/" + nodeId + "/register").c_str(), regPayload.c_str(), true);
	} else {
		Serial.print(" failed, rc=");
		Serial.println(mqtt.state());
		set_led_color(255, 0, 0);  // RED when disconnected
	}
}

void publish_heartbeat() {
	if (!mqtt.connected()) return;

	StaticJsonDocument<512> hb;
	hb["node_id"] = nodeId;
	hb["type"] = "gateway";
	hb["fw"] = fwVersion;
	hb["uptime"] = millis() / 1000;
	hb["clients"] = WiFi.softAPgetStationNum();
	hb["status"] = "active";

	char macStr[18];
	snprintf(macStr, sizeof(macStr), "%02x:%02x:%02x:%02x:%02x:%02x",
		gatewayMAC[0], gatewayMAC[1], gatewayMAC[2],
		gatewayMAC[3], gatewayMAC[4], gatewayMAC[5]);
	hb["mac"] = macStr;
	hb["ip"] = WiFi.softAPIP().toString();

	String hbPayload;
	serializeJson(hb, hbPayload);
	mqtt.publish(("nodes/" + nodeId + "/heartbeat").c_str(), hbPayload.c_str());
}

void publish_client_stats() {
	if (!mqtt.connected()) return;

	wifi_sta_list_t clients;
	esp_wifi_ap_get_sta_list(&clients);

	StaticJsonDocument<1024> stats;
	stats["clients"] = clients.num;

	JsonArray clientsArray = stats.createNestedArray("client_list");
	for (int i = 0; i < clients.num; i++) {
		JsonObject client = clientsArray.createNestedObject();
		char macStr[18];
		snprintf(macStr, sizeof(macStr), "%02x:%02x:%02x:%02x:%02x:%02x",
			clients.sta[i].mac[0], clients.sta[i].mac[1], clients.sta[i].mac[2],
			clients.sta[i].mac[3], clients.sta[i].mac[4], clients.sta[i].mac[5]);
		client["mac"] = macStr;
		client["rssi"] = clients.sta[i].rssi;
	}

	String statsPayload;
	serializeJson(stats, statsPayload);
	mqtt.publish(("nodes/" + nodeId + "/data/clients").c_str(), statsPayload.c_str());
}

// ===== Setup =====
void setup() {
	Serial.begin(115200);
	delay(1000);
	Serial.println("\n\n=== Gateway Starting ===");

	// Initialize LED to RED (not connected yet)
	set_led_color(255, 0, 0);

	prefs.begin("parley", false);

	setup_ap();

	mqtt.setServer(MQTT_BROKER, MQTT_PORT);
	mqtt.setCallback(mqtt_callback);
	mqtt.setKeepAlive(15);
	mqtt.setSocketTimeout(5);

	Serial.println("=== Gateway Ready ===\n");
}

// ===== Loop =====
void loop() {
	// Handle MQTT connection
	if (!mqtt.connected()) {
		set_led_color(255, 0, 0);  // RED when disconnected
		mqtt_reconnect();
	} else {
		set_led_color(0, 255, 0);  // GREEN when connected
		mqtt.loop();
	}

	unsigned long now = millis();

	// Publish heartbeat
	if (now - lastHeartbeat >= HEARTBEAT_INTERVAL) {
		lastHeartbeat = now;
		publish_heartbeat();
	}

	// Publish client stats
	if (now - lastPublish >= PUBLISH_INTERVAL) {
		lastPublish = now;
		publish_client_stats();
	}

	yield();
}
```

The key changes:

1. **LED initialization**: Set to RED at startup (line 106)
2. **Connection success**: Set to GREEN when MQTT connects (line 128)
3. **Connection failure**: Set to RED when MQTT connection fails (line 152)
4. **Loop monitoring**: Continuously updates LED in main loop based on MQTT connection state (lines 184-189)

The LED will now provide clear visual feedback:
- **🔴 RED**: Disconnected from Pi/MQTT broker
- **🟢 GREEN**: Connected to Pi and MQTT working

Upload this to your gateway and the LED will change to green once it successfully connects to the MQTT broker on the Pi.

